/* ============ learn content (ANALYST): 4 modules, lessons + quizzes ============ */
'use strict';

const ANALYST_MODULES = [
{
id:'threat', ico:'🔍',
title:{tr:'Tehdit Tespiti ve Analizi', en:'Threat Detection & Analysis'},
desc:{tr:'SIEM, alert triyajı, IoC/IoA, MITRE ATT&CK, Windows logları, phishing analizi.', en:'SIEM, alert triage, IoC/IoA, MITRE ATT&CK, Windows logs, phishing analysis.'},
lessons:[
{id:'siem', ico:'📊', title:{tr:'SIEM nasıl çalışır?', en:'How a SIEM works'},
body:{tr:`SIEM (Security Information & Event Management) akışı: <b>log toplama → normalizasyon → korelasyon → alert → triyaj</b>.<ul><li><b>Toplama:</b> Sunucular, firewall, EDR, AD, cloud... hepsinden log akar.</li><li><b>Normalizasyon:</b> Farklı formatlar ortak şemaya çevrilir.</li><li><b>Korelasyon:</b> Kurallar tek tek olayları birleştirir — ör. "5 dk içinde 20 başarısız oturum + 1 başarılı = brute force şüphesi".</li><li><b>Alert:</b> Kural tetiklenince analiste düşer; analist triyaj yapar.</li></ul>Örnek ürünler: Splunk, Microsoft Sentinel, QRadar, Wazuh (açık kaynak).`,
en:`SIEM (Security Information & Event Management) flow: <b>log collection → normalization → correlation → alert → triage</b>.<ul><li><b>Collection:</b> logs stream in from servers, firewalls, EDR, AD, cloud.</li><li><b>Normalization:</b> different formats are mapped to a common schema.</li><li><b>Correlation:</b> rules combine single events — e.g. "20 failed logons + 1 success within 5 minutes = brute-force suspicion".</li><li><b>Alert:</b> a triggered rule lands on an analyst's queue for triage.</li></ul>Examples: Splunk, Microsoft Sentinel, QRadar, Wazuh (open source).`},
say:`A SIEM collects and normalizes logs from many sources, correlates events against detection rules, and raises alerts that analysts then triage and investigate.`},
{id:'fpfn', ico:'⚖️', title:{tr:'False Positive vs False Negative', en:'False Positive vs False Negative'},
body:{tr:`<b>False Positive (FP):</b> Alarm var, gerçek tehdit yok — analistin vaktini yer, "alert fatigue" yaratır.<br><b>False Negative (FN):</b> Tehdit var, alarm yok — en tehlikelisi budur.<br><br>FP oranını düşürme yolları:<ul><li>Kuralları <b>tune</b> et: eşik değerlerini ortama göre ayarla.</li><li><b>Baseline</b> çıkar: "normal" davranışı öğren, sapmaya alarm ver.</li><li>Bilinen zararsız kaynakları <b>allowlist</b>'e al (ör. vuln tarayıcının IP'si).</li><li><b>Context</b> ekle: varlık kritikliği + threat intel ile zenginleştir.</li><li>Tek olaya değil <b>korelasyona</b> alarm ver.</li></ul>`,
en:`<b>False Positive (FP):</b> alert fires but there is no real threat — wastes analyst time, causes alert fatigue.<br><b>False Negative (FN):</b> a real threat with no alert — the most dangerous one.<br><br>Reducing FPs:<ul><li><b>Tune</b> rules: adjust thresholds to your environment.</li><li>Build a <b>baseline</b> of normal behavior; alert on deviation.</li><li><b>Allowlist</b> known-benign sources (e.g. the vulnerability scanner's IP).</li><li>Add <b>context</b>: asset criticality + threat intel enrichment.</li><li>Alert on <b>correlation</b>, not single events.</li></ul>`},
say:`A false positive is an alert without a real threat; a false negative is a real threat we missed. I reduce false positives by tuning thresholds, baselining normal behavior, allowlisting known-benign sources, and enriching alerts with asset and threat-intel context.`},
{id:'ioc', ico:'🧬', title:{tr:'IoC vs IoA', en:'IoC vs IoA'},
body:{tr:`<b>IoC (Indicator of Compromise):</b> Sistem <i>ele geçirilmiş olabilir</i>in kanıtı — statik artefakt.<br>Örnek: zararlı dosya <b>hash</b>'i, C2 sunucusunun <b>IP/domain</b>'i, bilinen zararlı dosya yolu.<br><br><b>IoA (Indicator of Attack):</b> Saldırganın <i>davranışını/niyetini</i> gösteren işaret — henüz başarılı olmamış bile olabilir.<br>Örnek: Word'ün <code>powershell.exe</code> başlatması, gece 3'te toplu dosya erişimi, olağandışı hesapla lateral movement denemesi.<br><br>Fark: IoC <b>geriye dönük</b> (olan olmuş), IoA <b>proaktif</b> (saldırı sürerken yakalarsın).`,
en:`<b>IoC (Indicator of Compromise):</b> evidence that a system <i>may already be compromised</i> — a static artifact.<br>Examples: a malicious file <b>hash</b>, a C2 <b>IP/domain</b>, a known bad file path.<br><br><b>IoA (Indicator of Attack):</b> a sign of attacker <i>behavior/intent</i> — possibly before success.<br>Examples: Word spawning <code>powershell.exe</code>, mass file access at 3 AM, lateral-movement attempts with an unusual account.<br><br>IoCs are <b>reactive</b> (it already happened); IoAs are <b>proactive</b> (catch the attack in progress).`},
say:`An IoC is a static artifact proving compromise — like a malicious hash or a C2 IP address. An IoA is behavioral — like Microsoft Word spawning PowerShell — and it lets you catch an attack while it is still in progress.`},
{id:'mitre', ico:'🗺️', title:{tr:'MITRE ATT&CK — 5 kritik taktik', en:'MITRE ATT&CK — 5 key tactics'},
body:{tr:`MITRE ATT&CK, saldırgan taktik ve tekniklerinin ortak dili. En azından şu 5'ini örnekle anlat:<ul><li><b>Initial Access:</b> İlk giriş — phishing eki, çalınan VPN hesabı, açık RDP.</li><li><b>Execution:</b> Kod çalıştırma — zararlı makro, PowerShell script.</li><li><b>Persistence:</b> Kalıcılık — registry run key, scheduled task, yeni servis (Event 7045).</li><li><b>Lateral Movement:</b> Yatay hareket — pass-the-hash, RDP, PsExec ile diğer makinelere sıçrama.</li><li><b>Exfiltration:</b> Veri kaçırma — DNS tüneli, cloud depoya upload, dışarı büyük transfer.</li></ul>Kullanımı: alert'i bir tekniğe eşle → saldırının hangi aşamada olduğunu ve sıradaki muhtemel adımı öngör.`,
en:`MITRE ATT&CK is the shared language of attacker tactics and techniques. Know at least these five with examples:<ul><li><b>Initial Access:</b> phishing attachment, stolen VPN account, exposed RDP.</li><li><b>Execution:</b> malicious macro, PowerShell script.</li><li><b>Persistence:</b> registry run key, scheduled task, new service (Event 7045).</li><li><b>Lateral Movement:</b> pass-the-hash, RDP, PsExec to other hosts.</li><li><b>Exfiltration:</b> DNS tunneling, upload to cloud storage, large outbound transfers.</li></ul>Usage: map an alert to a technique → know which stage the attack is in and predict the next step.`},
say:`I use MITRE ATT&CK to map alerts to attacker techniques. For example, a phishing email is Initial Access, a malicious macro is Execution, a registry run key is Persistence, pass-the-hash is Lateral Movement, and DNS tunneling is Exfiltration.`},
{id:'winlog', ico:'🪟', title:{tr:'Kritik Windows Event ID\'leri', en:'Key Windows Event IDs'},
body:{tr:`Ezbere bil — mülakatta somutluk puan getirir:<ul><li><code>4624</code> — Başarılı oturum açma (Logon Type 3 = ağ, 10 = RDP).</li><li><code>4625</code> — Başarısız oturum açma (brute force'un hammaddesi).</li><li><code>4688</code> — Yeni process oluşturma (şüpheli komutları buradan izlersin).</li><li><code>4672</code> — Özel yetkilerle oturum (admin logon'ları).</li><li><code>7045</code> — Yeni servis kuruldu (persistence işareti).</li><li><code>1102</code> — Denetim günlüğü silindi (<b>büyük kırmızı bayrak</b> — saldırgan iz temizliyor).</li></ul>`,
en:`Memorize these — concrete IDs score points in interviews:<ul><li><code>4624</code> — successful logon (Logon Type 3 = network, 10 = RDP).</li><li><code>4625</code> — failed logon (the raw material of brute-force detection).</li><li><code>4688</code> — new process created (watch suspicious command lines here).</li><li><code>4672</code> — logon with special privileges (admin logons).</li><li><code>7045</code> — new service installed (persistence signal).</li><li><code>1102</code> — audit log cleared (<b>huge red flag</b> — attacker covering tracks).</li></ul>`},
say:`In Windows logs, 4624 is a successful logon, 4625 is a failed logon, and 4688 is process creation. A burst of 4625 events followed by a 4624 from the same source suggests a successful brute-force attack, and Event 1102 — audit log cleared — is a major red flag.`},
{id:'phish', ico:'🎣', title:{tr:'Phishing e-posta triyajı', en:'Phishing email triage'},
body:{tr:`Şüpheli e-posta geldiğinde:<ul><li><b>Header analizi:</b> Gerçek gönderen IP'si, Return-Path, Reply-To uyuşmazlığı.</li><li><b>SPF:</b> Gönderen IP, domain'in yetkili sunucu listesinde mi?</li><li><b>DKIM:</b> Mesajın imzası geçerli mi (içerik değişmemiş mi)?</li><li><b>DMARC:</b> SPF/DKIM sonucuna göre politika (none/quarantine/reject).</li><li><b>URL analizi:</b> Link nereye gidiyor? Sandbox'ta / URL reputation servisinde aç, asla kendi makinede tıklama.</li><li><b>Ek analizi:</b> Hash'i al, sandbox'ta patlat (detonate), VirusTotal benzeri servise sor.</li><li><b>Kapsam:</b> Aynı e-posta başka kime gelmiş? Tıklayan var mı? → varsa parola sıfırlat, oturumları sonlandır.</li></ul>`,
en:`When a suspicious email is reported:<ul><li><b>Header analysis:</b> true sender IP, Return-Path, mismatched Reply-To.</li><li><b>SPF:</b> is the sending IP authorized for the domain?</li><li><b>DKIM:</b> is the signature valid (content untampered)?</li><li><b>DMARC:</b> policy applied based on SPF/DKIM results (none/quarantine/reject).</li><li><b>URL analysis:</b> where does the link really go? Open in a sandbox / URL reputation service, never on your own machine.</li><li><b>Attachment:</b> hash it, detonate in a sandbox, check a VirusTotal-like service.</li><li><b>Scope:</b> who else received it? Did anyone click? → if so, reset passwords, kill sessions.</li></ul>`},
say:`For a reported phishing email, I start with header analysis and check SPF, DKIM and DMARC results, then analyze URLs and attachments in a sandbox — never on my own machine. Finally I scope it: who else received it, and did anyone click.`},
{id:'triage', ico:'🚨', title:{tr:'Alert geldi — ilk 5 adım', en:'An alert fires — first 5 steps'},
body:{tr:`Mülakatın en muhtemel sorusu. Ezberle:<ul><li><b>1. Doğrula:</b> Ham loglara in — alert gerçek mi, kural hatası mı?</li><li><b>2. Kapsamı belirle:</b> Hangi makine, hangi kullanıcı, ne zamandır, başka nereye dokunmuş?</li><li><b>3. Bağlam ekle:</b> Varlık ne kadar kritik? Threat intel'de bu IP/hash geçiyor mu? Kullanıcının normal davranışı ne?</li><li><b>4. Sınıflandır:</b> True positive / false positive kararı ver; severity ata.</li><li><b>5. Aksiyon + belge:</b> TP ise playbook'u başlat (izole et / eskalasyon), her adımı ticket'a yaz.</li></ul>Altın cümle: <i>"Önce doğrularım, sonra kapsarım, asla panikle makine kapatmam — delil kaybederim."</i>`,
en:`The most likely interview question. Memorize:<ul><li><b>1. Validate:</b> go to raw logs — is the alert real or a rule error?</li><li><b>2. Scope:</b> which host, which user, since when, what else was touched?</li><li><b>3. Add context:</b> how critical is the asset? Does threat intel know this IP/hash? What is normal for this user?</li><li><b>4. Classify:</b> true positive / false positive; assign severity.</li><li><b>5. Act + document:</b> if TP, start the playbook (isolate / escalate), record every step in the ticket.</li></ul>Golden line: <i>"I validate first, then scope; I never power off a machine in panic — that destroys evidence."</i>`},
say:`My first steps are: validate the alert against raw logs, scope which hosts and users are affected, enrich with asset criticality and threat intelligence, classify it as true or false positive with a severity, and then act by playbook while documenting everything.`},
{id:'brute', ico:'🔨', title:{tr:'Brute force\'u loglardan yakalamak', en:'Detecting brute force in logs'},
body:{tr:`İmza: <b>kısa sürede çok sayıda 4625</b> (başarısız oturum), ardından aynı kaynaktan bir <b>4624</b> (başarılı) gelirse → hesap büyük ihtimalle düştü.<ul><li><b>Klasik brute force:</b> Tek hesap, çok parola → hesap bazlı eşik alarmı.</li><li><b>Password spraying:</b> Çok hesap, tek yaygın parola (kilitlenmeyi atlatır) → kaynak IP bazlı bak: bir IP'den onlarca farklı hesaba az sayıda deneme.</li><li>SIEM sorgusu mantığı: "aynı kaynak IP'den 5 dk'da >20 adet 4625 → alarm".</li><li>Aksiyon: kaynak IP'yi engelle, hedef hesap düştüyse parola sıfırla + oturumları kapat, MFA durumunu kontrol et.</li></ul>`,
en:`Signature: <b>many 4625 events in a short window</b>, and if a <b>4624</b> follows from the same source → the account likely fell.<ul><li><b>Classic brute force:</b> one account, many passwords → per-account threshold alert.</li><li><b>Password spraying:</b> many accounts, one common password (evades lockout) → look per source IP: one IP, dozens of accounts, few attempts each.</li><li>SIEM query logic: "more than 20 4625s from the same source IP within 5 minutes → alert".</li><li>Response: block the source IP; if an account fell, reset the password, kill sessions, verify MFA.</li></ul>`},
say:`I would look for a burst of Event 4625 failed logons from one source IP, and check whether a 4624 success follows. One account with many attempts is classic brute force; many accounts with few attempts each is password spraying. Then I block the source, reset affected credentials, and verify MFA.`}
],
quiz:[
{q:{tr:'SIEM korelasyonunun temel amacı nedir?', en:'What is the core purpose of SIEM correlation?'}, opts:[{tr:'Logları sıkıştırıp saklamak', en:'Compress and store logs'},{tr:'Tekil olayları birleştirip anlamlı saldırı desenleri bulmak', en:'Combine single events into meaningful attack patterns'},{tr:'Ağ trafiğini şifrelemek', en:'Encrypt network traffic'},{tr:'Yedekleme almak', en:'Take backups'}], a:1, expl:{tr:'Korelasyon, tek başına masum görünen olayları (20x 4625 + 1x 4624) birleştirerek saldırıyı görünür kılar.', en:'Correlation combines individually innocent events (20x 4625 + 1x 4624) to reveal the attack.'}},
{q:{tr:'Hangisi bir IoA (Indicator of Attack) örneğidir?', en:'Which one is an IoA (Indicator of Attack)?'}, opts:[{tr:'Bilinen zararlı dosya hash\'i', en:'A known malicious file hash'},{tr:'C2 sunucusunun IP adresi', en:'A C2 server IP address'},{tr:'Word\'ün powershell.exe başlatması', en:'Word spawning powershell.exe'},{tr:'Zararlı domain adı', en:'A malicious domain name'}], a:2, expl:{tr:'Hash/IP/domain statik IoC\'dir; Word→PowerShell davranışsal bir saldırı göstergesidir (IoA).', en:'Hash/IP/domain are static IoCs; Word→PowerShell is behavioral — an IoA.'}},
{q:{tr:'Event ID 4625 neyi gösterir?', en:'What does Event ID 4625 indicate?'}, opts:[{tr:'Başarılı oturum açma', en:'Successful logon'},{tr:'Başarısız oturum açma', en:'Failed logon'},{tr:'Process oluşturma', en:'Process creation'},{tr:'Log silinmesi', en:'Audit log cleared'}], a:1, expl:{tr:'4624 başarılı, 4625 başarısız, 4688 process creation, 1102 log silme.', en:'4624 success, 4625 failure, 4688 process creation, 1102 log cleared.'}},
{q:{tr:'Password spraying\'i klasik brute force\'tan ayıran nedir?', en:'What distinguishes password spraying from classic brute force?'}, opts:[{tr:'Tek hesaba çok parola denenir', en:'Many passwords against one account'},{tr:'Çok hesaba tek/az parola denenir', en:'One common password against many accounts'},{tr:'Sadece VPN\'e yapılır', en:'It only targets VPNs'},{tr:'Sadece gece yapılır', en:'It only happens at night'}], a:1, expl:{tr:'Spraying, hesap kilitleme eşiğini aşmamak için hesap başına az deneme yapar — kaynak IP bazlı tespit gerekir.', en:'Spraying stays under lockout thresholds with few attempts per account — detect per source IP.'}},
{q:{tr:'False negative neden false positive\'den daha tehlikelidir?', en:'Why is a false negative more dangerous than a false positive?'}, opts:[{tr:'Daha çok disk alanı kaplar', en:'It uses more disk space'},{tr:'Gerçek saldırı fark edilmeden ilerler', en:'A real attack proceeds undetected'},{tr:'Analisti yorar', en:'It tires the analyst'},{tr:'Raporlamayı bozar', en:'It breaks reporting'}], a:1, expl:{tr:'FP vakit kaybettirir ama FN görünmez bir ihlal demektir.', en:'FPs waste time, but an FN means an invisible breach.'}},
{q:{tr:'SPF kontrolü neyi doğrular?', en:'What does SPF verify?'}, opts:[{tr:'E-posta içeriğinin değişmediğini', en:'That the message content is untampered'},{tr:'Gönderen IP\'nin domain adına e-posta göndermeye yetkili olduğunu', en:'That the sending IP is authorized to send for the domain'},{tr:'Alıcının gerçek kişi olduğunu', en:'That the recipient is a real person'},{tr:'Ekin zararsız olduğunu', en:'That the attachment is benign'}], a:1, expl:{tr:'SPF = yetkili gönderici IP listesi. İçerik bütünlüğü DKIM\'in işi; politika DMARC\'ın.', en:'SPF = authorized sender IPs. Content integrity is DKIM; policy is DMARC.'}},
{q:{tr:'Registry run key eklenmesi MITRE ATT&CK\'te hangi taktiğe girer?', en:'Adding a registry run key maps to which ATT&CK tactic?'}, opts:[{tr:'Initial Access',en:'Initial Access'},{tr:'Persistence',en:'Persistence'},{tr:'Exfiltration',en:'Exfiltration'},{tr:'Lateral Movement',en:'Lateral Movement'}], a:1, expl:{tr:'Run key, yeniden başlatmada zararlının tekrar çalışmasını sağlar → kalıcılık (Persistence).', en:'A run key relaunches malware after reboot → Persistence.'}},
{q:{tr:'Alert triyajında İLK adım hangisi olmalı?', en:'What should be the FIRST step of alert triage?'}, opts:[{tr:'Makineyi hemen kapatmak', en:'Immediately power off the machine'},{tr:'Ham loglarla alert\'i doğrulamak', en:'Validate the alert against raw logs'},{tr:'CISO\'ya rapor yazmak', en:'Write a report to the CISO'},{tr:'Tüm parolaları sıfırlamak', en:'Reset all passwords'}], a:1, expl:{tr:'Önce doğrulama — FP olabilir. Makineyi kapatmak delil (RAM) kaybettirir.', en:'Validate first — it may be an FP. Powering off destroys volatile evidence.'}}
]},

{
id:'network', ico:'🌐',
title:{tr:'Ağ Güvenliği', en:'Network Security'},
desc:{tr:'TCP/IP, portlar, firewall/IDS/IPS, segmentasyon, VPN/TLS, DNS anomalileri, DDoS, MITM.', en:'TCP/IP, ports, firewall/IDS/IPS, segmentation, VPN/TLS, DNS anomalies, DDoS, MITM.'},
lessons:[
{id:'tcp', ico:'🤝', title:{tr:'TCP 3-way handshake', en:'TCP 3-way handshake'},
body:{tr:`Bağlantı kurulumu: <code>SYN</code> → <code>SYN-ACK</code> → <code>ACK</code>.<ul><li>İstemci SYN gönderir ("bağlanmak istiyorum").</li><li>Sunucu SYN-ACK döner ("tamam, ben de hazırım").</li><li>İstemci ACK ile onaylar → bağlantı kuruldu.</li></ul><b>Güvenlik bağlantısı:</b> SYN flood saldırısı bu mekanizmayı istismar eder — saldırgan ACK'yi hiç göndermez, sunucunun yarı açık bağlantı tablosu dolar ve meşru istekler reddedilir. Savunma: SYN cookies, rate limiting.`,
en:`Connection setup: <code>SYN</code> → <code>SYN-ACK</code> → <code>ACK</code>.<ul><li>Client sends SYN ("I want to connect").</li><li>Server replies SYN-ACK ("OK, I'm ready too").</li><li>Client confirms with ACK → connection established.</li></ul><b>Security angle:</b> a SYN flood abuses this — the attacker never sends the final ACK, the server's half-open connection table fills up, and legitimate requests are refused. Defense: SYN cookies, rate limiting.`},
say:`TCP opens a connection with a three-way handshake: SYN, SYN-ACK, ACK. A SYN flood abuses it by never completing the handshake, exhausting the server's half-open connection table — SYN cookies and rate limiting mitigate that.`},
{id:'ports', ico:'🚪', title:{tr:'Kritik portlar', en:'Critical ports'},
body:{tr:`Ezber listesi:<ul><li><code>21</code> FTP · <code>22</code> SSH · <code>23</code> Telnet (şifresiz — görürsen bayrak!)</li><li><code>25</code> SMTP · <code>53</code> DNS · <code>80</code> HTTP · <code>443</code> HTTPS</li><li><code>445</code> SMB (WannaCry/EternalBlue\'nun kapısı) · <code>3389</code> RDP (brute force mıknatısı)</li><li><code>3306</code> MySQL · <code>1433</code> MSSQL · <code>8080</code> HTTP alternatif</li></ul><b>Analist bakışı:</b> İnternete açık 3389/445 görmek = acil bulgu. Dışarı giden 53 trafiğinin anormal büyüklüğü = DNS tüneli şüphesi.`,
en:`Memorize:<ul><li><code>21</code> FTP · <code>22</code> SSH · <code>23</code> Telnet (cleartext — a finding if you see it!)</li><li><code>25</code> SMTP · <code>53</code> DNS · <code>80</code> HTTP · <code>443</code> HTTPS</li><li><code>445</code> SMB (WannaCry/EternalBlue's door) · <code>3389</code> RDP (brute-force magnet)</li><li><code>3306</code> MySQL · <code>1433</code> MSSQL · <code>8080</code> HTTP alt</li></ul><b>Analyst view:</b> 3389/445 exposed to the internet = urgent finding. Abnormally large outbound DNS = tunneling suspicion.`},
say:`Port 22 is SSH, 53 is DNS, 443 is HTTPS, 445 is SMB and 3389 is RDP. Seeing RDP or SMB exposed to the internet is an urgent finding, and unusually heavy outbound DNS traffic makes me suspect DNS tunneling.`},
{id:'fw', ico:'🧱', title:{tr:'Firewall vs IDS vs IPS', en:'Firewall vs IDS vs IPS'},
body:{tr:`<ul><li><b>Firewall:</b> Kurallara göre trafiği <b>geçirir/engeller</b> (port, IP, protokol). Ağın kapı bekçisi.</li><li><b>IDS:</b> Trafiği <b>izler ve alarm üretir</b>, engellemez. Genelde <i>out-of-band</i> (SPAN/TAP portundan kopya trafik alır) → trafiği yavaşlatmaz ama saldırıyı durdurmaz.</li><li><b>IPS:</b> IDS + <b>engelleme</b>. <i>Inline</i> durur (trafik içinden geçer) → durdurabilir ama FP durumunda meşru trafiği de keser, gecikme ekler.</li></ul><b>Yerleşim cevabı:</b> "IPS'i kritik segmentlerin önüne inline koyarım; IDS'i iç ağı geniş izlemek için SPAN portuna koyarım. IPS kuralları agresifse önce IDS modunda test ederim."`,
en:`<ul><li><b>Firewall:</b> <b>allows/blocks</b> traffic by rules (port, IP, protocol). The gatekeeper.</li><li><b>IDS:</b> <b>monitors and alerts</b>, doesn't block. Usually <i>out-of-band</i> (mirrored traffic via SPAN/TAP) → no latency, but doesn't stop attacks.</li><li><b>IPS:</b> IDS + <b>blocking</b>. Sits <i>inline</i> → can stop attacks, but a false positive also cuts legitimate traffic and adds latency.</li></ul><b>Placement answer:</b> "I'd put an IPS inline in front of critical segments, and an IDS on a SPAN port for broad internal visibility. Aggressive IPS rules I'd first test in IDS mode."`},
say:`An IDS detects and alerts out-of-band, while an IPS sits inline and actively blocks. The trade-off is that an IPS can stop attacks but a false positive blocks legitimate traffic, so I would run new rules in detection mode first, then enable blocking.`},
{id:'seg', ico:'🧩', title:{tr:'Segmentasyon, VLAN, Zero Trust', en:'Segmentation, VLANs, Zero Trust'},
body:{tr:`<b>Segmentasyon:</b> Ağı bölmelere ayır — saldırgan içeri girse bile <b>lateral movement</b>'ı sınırlanır (yangın kapıları gibi).<ul><li><b>VLAN:</b> Mantıksal bölme — finans, İK, sunucular, misafir Wi-Fi ayrı VLAN'larda.</li><li>Segmentler arası trafik firewall'dan geçmeli (sadece gereken portlar).</li><li><b>Zero Trust:</b> "İçerideysen güvenilirsin" varsayımını reddeder — her erişim kimlik + cihaz + bağlam ile sürekli doğrulanır.</li></ul>Örnek cümle: ransomware vakasında segmentasyon, şifrelemenin tüm ağa yayılmasını engelleyen en etkili mimari önlemdir.`,
en:`<b>Segmentation:</b> divide the network so an attacker who gets in has limited <b>lateral movement</b> (like fire doors).<ul><li><b>VLANs:</b> logical separation — finance, HR, servers, guest Wi-Fi on separate VLANs.</li><li>Inter-segment traffic must pass a firewall (only required ports).</li><li><b>Zero Trust:</b> rejects "inside = trusted" — every access is continuously verified by identity + device + context.</li></ul>Example line: in a ransomware case, segmentation is the single most effective architectural control against encryption spreading network-wide.`},
say:`Network segmentation limits lateral movement — even if one segment is compromised, fire-doors contain the blast radius. Zero Trust goes further: no user or device is trusted by default; every access is verified by identity, device posture and context.`},
{id:'vpn', ico:'🔐', title:{tr:'VPN ve TLS mantığı', en:'VPN and TLS'},
body:{tr:`<b>TLS:</b> İletişimi şifreler (HTTPS'in S'i).<ul><li>Handshake'te sunucu <b>sertifika</b> sunar → istemci, sertifika otoritesi (CA) zinciriyle doğrular.</li><li>Asimetrik kripto ile anahtar anlaşması yapılır, sonra hızlı simetrik şifrelemeye geçilir.</li><li>Sağladıkları: <b>gizlilik</b> (şifreleme), <b>bütünlük</b> (değiştirilememe), <b>kimlik doğrulama</b> (sunucunun gerçekten o olması).</li></ul><b>VPN:</b> İki nokta arasında şifreli <b>tünel</b> — uzaktan çalışan, kurum ağına sanki içerideymiş gibi güvenle bağlanır. Riski: çalınan VPN hesabı = kapıdan içeri davetiye → MFA şart.`,
en:`<b>TLS:</b> encrypts communication (the S in HTTPS).<ul><li>In the handshake the server presents a <b>certificate</b> → the client validates it against the CA chain.</li><li>Keys are agreed asymmetrically, then fast symmetric encryption takes over.</li><li>Provides: <b>confidentiality</b>, <b>integrity</b>, <b>authentication</b>.</li></ul><b>VPN:</b> an encrypted <b>tunnel</b> between two points — remote workers join the corporate network as if inside. Risk: a stolen VPN account is an invitation through the front door → MFA is mandatory.`},
say:`TLS gives us confidentiality, integrity and server authentication through certificates. A VPN builds an encrypted tunnel into the corporate network — which is also why a stolen VPN credential is so dangerous, and why MFA on VPN access is mandatory.`},
{id:'dns', ico:'🕳️', title:{tr:'DNS tünelleme ve anomaliler', en:'DNS tunneling & anomalies'},
body:{tr:`DNS genelde filtrelenmez — saldırganlar bunu <b>veri kaçırma ve C2</b> için kullanır.<br>Tespit işaretleri:<ul><li>Çok <b>uzun ve rastgele</b> görünen subdomain'ler: <code>a3f9x71b2...evil.com</code></li><li>Tek domain'e anormal <b>yüksek sorgu hacmi</b></li><li>Bol miktarda <b>TXT/NULL</b> kaydı sorgusu</li><li>Düzenli aralıklı sorgular = <b>beaconing</b> (zararlı, C2'ye "yaşıyorum" sinyali atıyor)</li></ul>Aksiyon: şüpheli domain'i threat intel'de ara, sorgu yapan host'u incele, DNS firewall / sinkhole uygula.`,
en:`DNS is rarely filtered — attackers abuse it for <b>exfiltration and C2</b>.<br>Detection signals:<ul><li>Very <b>long, random-looking</b> subdomains: <code>a3f9x71b2...evil.com</code></li><li>Abnormally <b>high query volume</b> to one domain</li><li>Lots of <b>TXT/NULL</b> record queries</li><li>Regularly spaced queries = <b>beaconing</b> (malware pinging its C2)</li></ul>Response: check the domain against threat intel, investigate the querying host, apply DNS firewall / sinkholing.`},
say:`DNS tunneling hides data inside DNS queries. I look for long random subdomains, high query volume to a single domain, unusual TXT record queries, and regular beaconing intervals — then I check the domain against threat intelligence and investigate the querying host.`},
{id:'shark', ico:'🦈', title:{tr:'Wireshark temelleri', en:'Wireshark basics'},
body:{tr:`Paket analizi aracın. Bilmen gereken minimum:<ul><li>Filtreler: <code>ip.addr == 10.0.0.5</code>, <code>tcp.port == 443</code>, <code>http</code>, <code>dns</code></li><li><code>tcp.flags.syn == 1 && tcp.flags.ack == 0</code> → SYN taraması avı</li><li><b>Follow TCP Stream:</b> Bir bağlantının tüm konuşmasını oku (şifresizse).</li><li>Statistics → Conversations: en çok konuşan çiftleri bul (exfil şüphesi).</li></ul>Mülakat cümlesi: "Şüpheli host'un pcap'inde önce conversations'a bakar, sonra ilgili stream'i takip ederim."`,
en:`Your packet analysis tool. Minimum to know:<ul><li>Filters: <code>ip.addr == 10.0.0.5</code>, <code>tcp.port == 443</code>, <code>http</code>, <code>dns</code></li><li><code>tcp.flags.syn == 1 && tcp.flags.ack == 0</code> → hunting SYN scans</li><li><b>Follow TCP Stream:</b> read a connection's full conversation (if unencrypted).</li><li>Statistics → Conversations: find the top talkers (exfil suspicion).</li></ul>Interview line: "In the suspicious host's pcap I'd check Conversations first, then follow the relevant stream."`},
say:`In Wireshark I filter by IP or port, use Follow TCP Stream to read a full conversation, and check Statistics, Conversations to spot top talkers — which quickly surfaces exfiltration or scanning behavior.`},
{id:'ddos', ico:'🌊', title:{tr:'DDoS türleri', en:'DDoS types'},
body:{tr:`Üç katman:<ul><li><b>Volumetrik:</b> Bant genişliğini boğ (UDP flood, DNS amplification). Ölçü: Gbps.</li><li><b>Protokol:</b> Altyapı kaynaklarını tüket (SYN flood — yarı açık bağlantılar). Ölçü: paket/sn.</li><li><b>Uygulama katmanı (L7):</b> Az trafikle pahalı istekler (HTTP flood, ağır arama sorguları). En sinsi olanı — normal kullanıcı gibi görünür.</li></ul>Savunma: CDN + rate limiting + scrubbing servisi (Cloudflare benzeri), SYN cookies, otomatik ölçekleme.`,
en:`Three layers:<ul><li><b>Volumetric:</b> saturate bandwidth (UDP flood, DNS amplification). Measured in Gbps.</li><li><b>Protocol:</b> exhaust infrastructure state (SYN flood — half-open connections). Measured in packets/sec.</li><li><b>Application layer (L7):</b> cheap-looking but expensive requests (HTTP flood, heavy search queries). The sneakiest — looks like normal users.</li></ul>Defense: CDN + rate limiting + scrubbing service (Cloudflare-like), SYN cookies, autoscaling.`},
say:`DDoS attacks come in three flavors: volumetric floods that saturate bandwidth, protocol attacks like SYN floods that exhaust connection state, and application-layer floods that look like real users. Mitigation combines a CDN, rate limiting and a scrubbing service.`},
{id:'mitm', ico:'🕵️', title:{tr:'MITM — Man in the Middle', en:'MITM — Man in the Middle'},
body:{tr:`Saldırgan, iki taraf arasına girer; trafiği <b>okur veya değiştirir</b>.<ul><li><b>ARP spoofing:</b> Yerel ağda "gateway benim" yalanı → trafik saldırgandan geçer.</li><li><b>Rogue AP / Evil twin:</b> Sahte Wi-Fi ("Airport_Free_WiFi") kurup kurbanları bağlamak.</li><li><b>DNS spoofing:</b> Kurbanı sahte siteye yönlendirme.</li></ul>Önlemler: her yerde <b>TLS/HTTPS + HSTS</b>, kritik uygulamada certificate pinning, ağda <b>dynamic ARP inspection + DHCP snooping</b>, güvenilmeyen Wi-Fi'da VPN.`,
en:`The attacker sits between two parties and <b>reads or alters</b> traffic.<ul><li><b>ARP spoofing:</b> "I am the gateway" lie on the LAN → traffic flows through the attacker.</li><li><b>Rogue AP / evil twin:</b> fake Wi-Fi ("Airport_Free_WiFi") luring victims.</li><li><b>DNS spoofing:</b> redirecting victims to a fake site.</li></ul>Defenses: <b>TLS/HTTPS + HSTS</b> everywhere, certificate pinning for critical apps, <b>dynamic ARP inspection + DHCP snooping</b> on the network, VPN on untrusted Wi-Fi.`},
say:`In a man-in-the-middle attack, the attacker intercepts traffic — for example via ARP spoofing on a LAN or an evil-twin Wi-Fi access point. TLS with HSTS, certificate pinning, dynamic ARP inspection and using a VPN on untrusted networks are the main defenses.`}
],
quiz:[
{q:{tr:'3-way handshake\'in doğru sırası nedir?', en:'What is the correct 3-way handshake order?'}, opts:[{tr:'ACK → SYN → SYN-ACK', en:'ACK → SYN → SYN-ACK'},{tr:'SYN → SYN-ACK → ACK', en:'SYN → SYN-ACK → ACK'},{tr:'SYN → ACK → FIN', en:'SYN → ACK → FIN'},{tr:'SYN-ACK → SYN → ACK', en:'SYN-ACK → SYN → ACK'}], a:1, expl:{tr:'SYN (istemci) → SYN-ACK (sunucu) → ACK (istemci).', en:'SYN (client) → SYN-ACK (server) → ACK (client).'}},
{q:{tr:'3389 portu hangi servise aittir?', en:'Port 3389 belongs to which service?'}, opts:[{tr:'SSH',en:'SSH'},{tr:'SMB',en:'SMB'},{tr:'RDP',en:'RDP'},{tr:'DNS',en:'DNS'}], a:2, expl:{tr:'3389 = RDP. İnternete açık RDP, brute force ve fidye yazılımı vakalarının klasik giriş kapısıdır.', en:'3389 = RDP. Internet-exposed RDP is a classic entry point for brute force and ransomware.'}},
{q:{tr:'IPS\'in IDS\'e göre temel farkı nedir?', en:'What is the key difference of an IPS vs an IDS?'}, opts:[{tr:'Sadece alarm üretir', en:'It only generates alerts'},{tr:'Inline durur ve trafiği engelleyebilir', en:'It sits inline and can block traffic'},{tr:'Log toplamaz', en:'It does not collect logs'},{tr:'Sadece cloud\'da çalışır', en:'It only runs in the cloud'}], a:1, expl:{tr:'IDS izler/alarm verir (out-of-band); IPS inline durup engeller — FP riski meşru trafiği kesmektir.', en:'IDS monitors out-of-band; IPS is inline and blocks — an FP can cut legitimate traffic.'}},
{q:{tr:'Uzun rastgele subdomain\'lere yoğun DNS sorgusu neyin işaretidir?', en:'Heavy DNS queries to long random subdomains signal what?'}, opts:[{tr:'Normal CDN trafiği', en:'Normal CDN traffic'},{tr:'DNS tünelleme / exfiltration', en:'DNS tunneling / exfiltration'},{tr:'SYN flood', en:'SYN flood'},{tr:'ARP spoofing', en:'ARP spoofing'}], a:1, expl:{tr:'Veri, subdomain içine kodlanarak DNS üzerinden dışarı sızdırılır.', en:'Data is encoded into subdomains and exfiltrated over DNS.'}},
{q:{tr:'SYN flood hangi DDoS kategorisine girer?', en:'A SYN flood belongs to which DDoS category?'}, opts:[{tr:'Volumetrik', en:'Volumetric'},{tr:'Protokol', en:'Protocol'},{tr:'Uygulama katmanı', en:'Application layer'},{tr:'Fiziksel', en:'Physical'}], a:1, expl:{tr:'SYN flood, sunucunun bağlantı tablosunu (state) tüketir → protokol saldırısı.', en:'SYN floods exhaust the server\'s connection state → protocol attack.'}},
{q:{tr:'ARP spoofing\'e karşı ağ tarafında en doğru önlem hangisi?', en:'Best network-side control against ARP spoofing?'}, opts:[{tr:'Güçlü parola politikası', en:'Strong password policy'},{tr:'Dynamic ARP Inspection + DHCP snooping', en:'Dynamic ARP Inspection + DHCP snooping'},{tr:'Antivirüs', en:'Antivirus'},{tr:'Yedekleme', en:'Backups'}], a:1, expl:{tr:'DAI, ARP paketlerini DHCP snooping tablosuyla doğrular; sahte "ben gateway\'im" iddialarını düşürür.', en:'DAI validates ARP packets against the DHCP snooping table, dropping fake gateway claims.'}},
{q:{tr:'Zero Trust\'ın temel ilkesi nedir?', en:'What is the core principle of Zero Trust?'}, opts:[{tr:'İç ağdaki her şeye güven', en:'Trust everything inside the network'},{tr:'Hiçbir erişime varsayılan güven yok; sürekli doğrula', en:'No default trust; verify every access continuously'},{tr:'Sadece VPN kullan', en:'Use only VPNs'},{tr:'Tüm portları kapat', en:'Close all ports'}], a:1, expl:{tr:'"Never trust, always verify" — kimlik + cihaz + bağlam her erişimde doğrulanır.', en:'"Never trust, always verify" — identity + device + context checked on every access.'}},
{q:{tr:'Şüpheli bir bağlantının tam içeriğini Wireshark\'ta nasıl okursun?', en:'How do you read a suspicious connection\'s full content in Wireshark?'}, opts:[{tr:'Statistics → Endpoints', en:'Statistics → Endpoints'},{tr:'Follow TCP Stream', en:'Follow TCP Stream'},{tr:'Capture → Restart', en:'Capture → Restart'},{tr:'View → Coloring Rules', en:'View → Coloring Rules'}], a:1, expl:{tr:'Follow TCP Stream, o bağlantının tüm konuşmasını birleştirip gösterir.', en:'Follow TCP Stream reassembles and shows the whole conversation.'}}
]},

{
id:'ir', ico:'🚒',
title:{tr:'Olay Müdahalesi (IR)', en:'Incident Response'},
desc:{tr:'NIST 800-61 yaşam döngüsü, containment, ransomware playbook, delil bütünlüğü, raporlama.', en:'NIST 800-61 lifecycle, containment, ransomware playbook, chain of custody, reporting.'},
lessons:[
{id:'nist', ico:'🔄', title:{tr:'NIST 800-61 yaşam döngüsü', en:'NIST 800-61 lifecycle'},
body:{tr:`6 faz — sırası ezbere, her faza 1 örnek:<ul><li><b>1. Preparation:</b> Playbook'lar, eğitim, loglama altyapısı, iletişim planı hazır.</li><li><b>2. Detection & Analysis:</b> Alert doğrulama, kapsam çıkarma, severity atama.</li><li><b>3. Containment:</b> Yayılmayı durdur — makineyi izole et, hesabı kilitle (kısa vade) / yeniden kurulum planı (uzun vade).</li><li><b>4. Eradication:</b> Kök nedeni ve zararlıyı ortadan kaldır — malware sil, açığı yamala, saldırgan hesaplarını kapat.</li><li><b>5. Recovery:</b> Sistemleri temiz halde üretime döndür, bir süre yakın izle.</li><li><b>6. Lessons Learned:</b> Post-mortem toplantısı, rapor, tespit kurallarını ve playbook'u güncelle.</li></ul>`,
en:`Six phases — know the order cold, one example each:<ul><li><b>1. Preparation:</b> playbooks, training, logging infrastructure, comms plan ready.</li><li><b>2. Detection & Analysis:</b> validate alerts, scope, assign severity.</li><li><b>3. Containment:</b> stop the spread — isolate the host, lock the account (short term) / rebuild plan (long term).</li><li><b>4. Eradication:</b> remove root cause and malware — delete, patch, close attacker accounts.</li><li><b>5. Recovery:</b> return clean systems to production, monitor closely for a while.</li><li><b>6. Lessons Learned:</b> post-mortem, report, update detections and playbooks.</li></ul>`},
say:`I follow the NIST incident response lifecycle: Preparation, Detection and Analysis, Containment, Eradication, Recovery, and Lessons Learned. For example with malware: we isolate the host to contain it, remove the malware and patch the root cause, restore from clean backups, and finish with a post-mortem that improves our detections.`},
{id:'contain', ico:'🧯', title:{tr:'Containment: kısa vs uzun vade', en:'Containment: short vs long term'},
body:{tr:`<b>Kısa vadeli containment</b> — kanamayı durdur:<ul><li>Makineyi ağdan izole et (kapatma! RAM delili gider).</li><li>Hesabı devre dışı bırak, oturumları sonlandır.</li><li>Zararlı IP/domain'i firewall'da engelle.</li></ul><b>Uzun vadeli containment</b> — kalıcı çözüm hazırlanırken güvenli çalışma:<ul><li>Temiz sistemden geçici hizmet, sıkılaştırılmış kurallar, ek izleme.</li></ul><b>İş etkisi dengesi:</b> "Üretim sunucusunu izole etmeden önce iş sahibiyle etkisini konuşurum ama aktif exfiltration varsa önce keserim" — bu cümle olgunluk gösterir.`,
en:`<b>Short-term containment</b> — stop the bleeding:<ul><li>Isolate the machine from the network (don't power off! You lose RAM evidence).</li><li>Disable the account, kill sessions.</li><li>Block malicious IPs/domains at the firewall.</li></ul><b>Long-term containment</b> — operate safely while the permanent fix is prepared:<ul><li>Temporary service from clean systems, hardened rules, extra monitoring.</li></ul><b>Business balance:</b> "Before isolating a production server I'd check impact with the business owner — but if there's active exfiltration, I cut first." That sentence signals maturity.`},
say:`Short-term containment stops the bleeding — isolate the host from the network without powering it off, disable compromised accounts, block malicious IPs. Long-term containment keeps the business running safely until eradication — hardened temporary systems and extra monitoring.`},
{id:'ransom', ico:'💀', title:{tr:'Ransomware playbook', en:'Ransomware playbook'},
body:{tr:`"Sunucuda ransomware tespit edildi" sorusunun adım adım cevabı:<ul><li><b>1. İzole et:</b> Ağ bağlantısını kes (kapatma — şifreleme anahtarı RAM'de olabilir).</li><li><b>2. Kapsamı çıkar:</b> Başka hangi sistemlerde aynı IoC var? Yayılıyor mu? Paylaşımlar, yedekler etkilenmiş mi?</li><li><b>3. Eskale et & bildir:</b> IR ekibi, yönetim, gerekirse hukuk — KVKK/GDPR bildirimi gerekebilir.</li><li><b>4. Delil topla:</b> Bellek imajı, disk imajı, loglar — hash'le, chain of custody başlat.</li><li><b>5. Türü tespit et:</b> Not/uzantıdan strain'i belirle; giriş vektörünü bul (phishing? RDP? açık?).</li><li><b>6. Eradication:</b> Zararlıyı temizle, giriş kapısını kapat (yama, parola, MFA).</li><li><b>7. Recovery:</b> <b>Temiz (offline) yedekten</b> dön; yedeklerin de şifrelenmediğini doğrula.</li><li><b>8. Lessons learned:</b> Rapor + segmentasyon/yedek stratejisi iyileştirmeleri.</li></ul><b>Fidye ödenmez</b> (garanti yok + hedef haline gelirsin) — karar yönetim/hukuk seviyesindedir, analist önerir.`,
en:`Step-by-step answer for "ransomware detected on a server":<ul><li><b>1. Isolate:</b> cut network access (don't power off — encryption keys may be in RAM).</li><li><b>2. Scope:</b> which other systems show the same IoCs? Is it spreading? Are shares/backups hit?</li><li><b>3. Escalate & notify:</b> IR team, management, legal if needed — regulatory notification may apply.</li><li><b>4. Preserve evidence:</b> memory image, disk image, logs — hash them, start chain of custody.</li><li><b>5. Identify strain & entry:</b> from the note/extension; find the vector (phishing? RDP? vuln?).</li><li><b>6. Eradicate:</b> remove malware, close the entry point (patch, passwords, MFA).</li><li><b>7. Recover:</b> restore from <b>clean offline backups</b>; verify backups weren't encrypted too.</li><li><b>8. Lessons learned:</b> report + segmentation/backup improvements.</li></ul><b>Don't pay the ransom</b> (no guarantee + you become a repeat target) — that call is management/legal level; the analyst advises.`},
say:`First I isolate the server from the network — but I don't power it off, because encryption keys and evidence live in memory. Then I scope the spread, escalate to the IR team and management, preserve forensic evidence, identify the strain and the entry vector, eradicate, restore from clean offline backups, and close with lessons learned.`},
{id:'chain', ico:'⛓️', title:{tr:'Delil bütünlüğü — Chain of Custody', en:'Chain of custody'},
body:{tr:`Delilin mahkemede/soruşturmada geçerli olması için:<ul><li>Delili kim, ne zaman, nereden aldı, kime devretti — <b>hepsi kayıt altında</b>.</li><li>Orijinal disk asla doğrudan incelenmez → <b>imaj alınır</b>, incelemeler kopyada yapılır.</li><li>İmajın <b>hash'i</b> (SHA-256) alınır → sonradan değişmediği kanıtlanır.</li><li>Uçucu veriler önce: RAM → çalışan process/bağlantılar → disk (volatility order).</li></ul>`,
en:`For evidence to hold up in court/investigation:<ul><li>Who collected it, when, from where, who received it — <b>all logged</b>.</li><li>Never examine the original disk directly → take an <b>image</b>, analyze the copy.</li><li><b>Hash</b> the image (SHA-256) → proves it wasn't altered later.</li><li>Volatile data first: RAM → running processes/connections → disk (order of volatility).</li></ul>`},
say:`Chain of custody means documenting who handled the evidence, when and how. We image disks instead of touching originals, hash the images to prove integrity, and collect volatile data like RAM before it disappears.`},
{id:'esc', ico:'📞', title:{tr:'Ne zaman eskale edilir?', en:'When to escalate'},
body:{tr:`Analist her şeyi tek başına çözmez — <b>doğru zamanda eskalasyon olgunluktur</b>:<ul><li>Kritik varlık etkilendiyse (domain controller, müşteri verisi, üretim DB).</li><li>Olay <b>aktif yayılıyorsa</b> ya da veri sızıntısı şüphesi varsa.</li><li>Yetkini aşan aksiyon gerekiyorsa (üretim sistemini kapatmak, müşteri bildirimi).</li><li>Yasal/regülasyon boyutu varsa (kişisel veri → hukuk ekibi, KVKK/GDPR).</li></ul>Cümle kalıbı: "Belirlenen severity eşiklerine göre L2/IR ekibine, playbook'taki iletişim planıyla eskale ederim; olay iletişimini tek kanaldan yürütürüm."`,
en:`An analyst doesn't solve everything alone — <b>escalating at the right time is maturity</b>:<ul><li>A critical asset is affected (domain controller, customer data, production DB).</li><li>The incident is <b>actively spreading</b> or data exfiltration is suspected.</li><li>An action beyond your authority is needed (shutting production, customer notification).</li><li>There's a legal/regulatory angle (personal data → legal team, GDPR).</li></ul>Template: "I escalate to L2/IR per our severity thresholds using the playbook's comms plan, and keep incident communication on a single channel."`},
say:`I escalate when a critical asset is involved, when the incident is actively spreading or data may be leaving, when an action exceeds my authority, or when there is a legal dimension. Escalation follows the playbook's severity thresholds and communication plan.`},
{id:'report', ico:'📝', title:{tr:'Olay sonrası rapor', en:'Post-incident report'},
body:{tr:`İyi bir raporun bölümleri:<ul><li><b>Özet:</b> Ne oldu, etki ne, şu an durum ne (yönetici dili — 5 cümle).</li><li><b>Zaman çizelgesi:</b> İlk tespitten kapanışa, saat saat.</li><li><b>Kök neden:</b> Giriş vektörü ve neden başarılı oldu.</li><li><b>Etki:</b> Hangi sistemler/veriler, ne kadar süre, iş etkisi.</li><li><b>Alınan aksiyonlar:</b> Containment'tan recovery'ye yapılanlar.</li><li><b>IoC listesi:</b> Hash, IP, domain — tespit kurallarına eklenecekler.</li><li><b>Öneriler / Lessons learned:</b> Somut, sahipli, tarihli iyileştirmeler ("MFA'yı VPN'e ekle — IT — 2 hafta").</li></ul>`,
en:`Sections of a good report:<ul><li><b>Executive summary:</b> what happened, impact, current status (5 sentences, exec language).</li><li><b>Timeline:</b> first detection to closure, hour by hour.</li><li><b>Root cause:</b> entry vector and why it worked.</li><li><b>Impact:</b> which systems/data, for how long, business impact.</li><li><b>Actions taken:</b> containment through recovery.</li><li><b>IoC list:</b> hashes, IPs, domains — to feed detection rules.</li><li><b>Recommendations / lessons learned:</b> concrete, owned, dated ("add MFA to VPN — IT — 2 weeks").</li></ul>`},
say:`A post-incident report contains an executive summary, a detailed timeline, root cause, impact assessment, the actions we took, the IoCs we extracted, and concrete recommendations with owners and deadlines — so the same incident cannot happen the same way twice.`}
],
quiz:[
{q:{tr:'NIST IR yaşam döngüsünde Containment\'tan hemen sonra ne gelir?', en:'In the NIST IR lifecycle, what comes right after Containment?'}, opts:[{tr:'Recovery',en:'Recovery'},{tr:'Eradication',en:'Eradication'},{tr:'Lessons Learned',en:'Lessons Learned'},{tr:'Preparation',en:'Preparation'}], a:1, expl:{tr:'Sıra: Preparation → Detection & Analysis → Containment → Eradication → Recovery → Lessons Learned.', en:'Order: Preparation → Detection & Analysis → Containment → Eradication → Recovery → Lessons Learned.'}},
{q:{tr:'Ransomware bulaşan sunucuya ilk müdahale ne olmalı?', en:'First action on a ransomware-infected server?'}, opts:[{tr:'Hemen kapat', en:'Power it off immediately'},{tr:'Ağdan izole et ama açık tut', en:'Isolate from network but keep it on'},{tr:'Fidyeyi öde', en:'Pay the ransom'},{tr:'Format at', en:'Reformat it'}], a:1, expl:{tr:'Kapatmak RAM\'deki delilleri ve olası şifreleme anahtarlarını yok eder; izolasyon yayılmayı durdurur.', en:'Powering off destroys RAM evidence and possible keys; isolation stops the spread.'}},
{q:{tr:'Containment ile Eradication farkı nedir?', en:'Containment vs Eradication?'}, opts:[{tr:'Aynı şeydir', en:'They are the same'},{tr:'Containment yayılmayı sınırlar; Eradication kök nedeni ve zararlıyı kaldırır', en:'Containment limits spread; Eradication removes root cause and malware'},{tr:'Eradication önce gelir', en:'Eradication comes first'},{tr:'Containment sadece rapor yazmaktır', en:'Containment is just reporting'}], a:1, expl:{tr:'Önce kanamayı durdur (contain), sonra hastalığı tedavi et (eradicate).', en:'First stop the bleeding (contain), then cure the disease (eradicate).'}},
{q:{tr:'Delil toplarken doğru sıra hangisi?', en:'Correct evidence collection order?'}, opts:[{tr:'Disk → RAM → loglar', en:'Disk → RAM → logs'},{tr:'RAM (uçucu) → çalışan bağlantılar → disk', en:'RAM (volatile) → live connections → disk'},{tr:'Önce format, sonra imaj', en:'Format first, then image'},{tr:'Sıra önemli değil', en:'Order does not matter'}], a:1, expl:{tr:'Order of volatility: en uçucu veri (RAM) önce toplanır — kapatınca kaybolur.', en:'Order of volatility: most volatile (RAM) first — it vanishes on shutdown.'}},
{q:{tr:'Hangi durumda eskalasyon ŞARTTIR?', en:'Which situation REQUIRES escalation?'}, opts:[{tr:'Tekil FP alert', en:'A single FP alert'},{tr:'Domain controller\'da aktif şüpheli aktivite', en:'Active suspicious activity on a domain controller'},{tr:'Rutin yama', en:'Routine patching'},{tr:'Kullanıcının parola unutması', en:'A user forgot a password'}], a:1, expl:{tr:'DC = krallığın anahtarları. Kritik varlık + aktif tehdit = anında eskalasyon.', en:'The DC holds the keys to the kingdom. Critical asset + active threat = escalate now.'}},
{q:{tr:'Yedekten dönmeden önce en kritik kontrol nedir?', en:'Most critical check before restoring from backup?'}, opts:[{tr:'Yedeğin temiz ve şifrelenmemiş olduğunu doğrulamak', en:'Verify the backup is clean and not encrypted'},{tr:'Yedeğin boyutu', en:'The backup size'},{tr:'Yedeğin rengi', en:'The backup label color'},{tr:'Hiçbiri', en:'None'}], a:0, expl:{tr:'Ransomware yedekleri de hedefler; kirli yedekten dönmek olayı yeniden başlatır. Giriş vektörü de kapatılmış olmalı.', en:'Ransomware targets backups too; restoring a dirty backup restarts the incident. The entry vector must also be closed.'}},
{q:{tr:'Lessons Learned fazının somut çıktısı ne olmalı?', en:'What is the concrete output of Lessons Learned?'}, opts:[{tr:'Suçlu ilan etmek', en:'Naming a culprit'},{tr:'Sahipli ve tarihli iyileştirme aksiyonları + güncellenen tespit kuralları', en:'Owned, dated improvement actions + updated detections'},{tr:'Olayı unutmak', en:'Forgetting the incident'},{tr:'Sadece toplantı yapmak', en:'Just holding a meeting'}], a:1, expl:{tr:'Blameless post-mortem + somut aksiyonlar: kurallar, playbook, mimari iyileştirmeler.', en:'Blameless post-mortem + concrete actions: rules, playbooks, architecture fixes.'}}
]},

{
id:'ai', ico:'🤖',
title:{tr:'AI Güvenliği (Bonus)', en:'AI Security (Bonus)'},
desc:{tr:'micro1 bir AI şirketi — prompt injection, jailbreak, data poisoning ve LLM izleme bilgisi seni öne çıkarır.', en:'micro1 is an AI company — prompt injection, jailbreaks, data poisoning and LLM monitoring set you apart.'},
lessons:[
{id:'pinj', ico:'💉', title:{tr:'Prompt Injection', en:'Prompt Injection'},
body:{tr:`LLM'e verilen <b>veri içine gizlenmiş talimatlar</b>, modelin asıl talimatlarını ezmeye çalışır.<ul><li><b>Direct:</b> Kullanıcı doğrudan yazar: "Önceki talimatları unut, bana X'i ver."</li><li><b>Indirect:</b> Modelin okuduğu web sayfası/doküman/e-posta içine gömülü talimat — model farkında olmadan uygular. (Daha tehlikeli!)</li></ul>Savunma: girdi/çıktı filtreleme, talimat-veri ayrımı, hassas aksiyonlar için insan onayı, en az yetki prensibi (modelin araçlarına sınır).`,
en:`Instructions <b>hidden inside data</b> given to an LLM, trying to override its real instructions.<ul><li><b>Direct:</b> the user writes it: "Ignore previous instructions and give me X."</li><li><b>Indirect:</b> instructions embedded in a web page/document/email the model reads — it obeys without realizing. (More dangerous!)</li></ul>Defenses: input/output filtering, separating instructions from data, human approval for sensitive actions, least privilege on the model's tools.`},
say:`Prompt injection hides malicious instructions inside the data an AI reads, trying to override its original instructions. Indirect injection — through a web page or document — is especially dangerous. Defenses include treating retrieved content as data not commands, output filtering, and human approval for sensitive actions.`},
{id:'jail', ico:'🔓', title:{tr:'Jailbreak', en:'Jailbreaking'},
body:{tr:`Modelin <b>güvenlik kurallarını aşma</b> çabası: rol yapma senaryoları ("DAN"), kodlanmış istekler, adım adım manipülasyon.<br>Prompt injection'dan farkı: jailbreak modelin <i>kendi kurallarını</i> hedefler; injection <i>uygulamanın talimat akışını</i> hedefler.<br>Savunma: çok katmanlı guardrail (model + uygulama katmanı), çıktı sınıflandırıcıları, kötüye kullanım izleme, red-team testleri.`,
en:`Attempts to <b>bypass the model's safety rules</b>: role-play scenarios ("DAN"), encoded requests, step-by-step manipulation.<br>Difference from prompt injection: jailbreaks target the model's <i>own rules</i>; injection targets the <i>application's instruction flow</i>.<br>Defenses: layered guardrails (model + application), output classifiers, abuse monitoring, red-team testing.`},
say:`A jailbreak tries to trick the model into ignoring its safety rules — through role-play or encoded requests. It differs from prompt injection, which targets the application's instruction flow. Layered guardrails, output classifiers and continuous red-teaming are the standard defenses.`},
{id:'poison', ico:'☠️', title:{tr:'Data Poisoning', en:'Data Poisoning'},
body:{tr:`Eğitim/fine-tune verisine <b>kasıtlı bozuk örnekler</b> sokarak modelin davranışını değiştirmek — ör. belirli bir tetikleyicide arka kapı gibi davranması.<br>RAG sistemlerinde eşdeğeri: bilgi tabanına zehirli doküman eklemek.<br>Savunma: veri kaynağı doğrulama, tedarik zinciri güvenliği, anomali tespiti, eğitim verisi denetimi.`,
en:`Planting <b>malicious samples into training/fine-tuning data</b> to alter model behavior — e.g. a backdoor that activates on a trigger.<br>The RAG equivalent: poisoning documents in the knowledge base.<br>Defenses: data provenance verification, supply-chain security, anomaly detection, training-data audits.`},
say:`Data poisoning plants malicious samples into training data or a RAG knowledge base to change model behavior — even creating hidden backdoors. Defenses focus on data provenance, supply-chain controls and auditing what goes into training.`},
{id:'leak', ico:'🫗', title:{tr:'Çıktı yoluyla veri sızıntısı', en:'Data leakage via outputs'},
body:{tr:`Model, eğitim verisindeki ya da bağlamındaki <b>hassas veriyi çıktısında ifşa edebilir</b>: PII, API anahtarları, dahili dokümanlar.<ul><li>System prompt'ta sır tutma — prompt'lar sızdırılabilir.</li><li>Çıktı tarafında DLP/regex filtreleri (API key, kimlik no desenleri).</li><li>RAG'de erişim kontrolü: kullanıcı, yetkisi olmayan dokümanın özetini alamamalı.</li></ul>`,
en:`A model may <b>expose sensitive data in its outputs</b>: PII, API keys, internal documents from training data or context.<ul><li>Never keep secrets in the system prompt — prompts can be extracted.</li><li>Output-side DLP/regex filters (API key, ID number patterns).</li><li>Access control in RAG: users must not get summaries of documents they can't access.</li></ul>`},
say:`Models can leak sensitive data through their outputs — PII, API keys, or internal documents. Controls include never storing secrets in prompts, output-side DLP filtering, and enforcing document-level access control in retrieval systems.`},
{id:'secops', ico:'🛰️', title:{tr:'AI sistemlerini izlemek = yine SOC işi', en:'Monitoring AI systems = still SOC work'},
body:{tr:`micro1 rolü büyük ihtimalle <b>AI sistemlerinin güvenlik operasyonu</b> — klasik becerilerin doğrudan geçer:<ul><li>LLM API loglarını izle: anomali desenleri (bir kullanıcıdan patlayan istek hacmi, sistematik jailbreak denemeleri).</li><li>Injection/jailbreak girişimleri = yeni nesil "alert" → aynı triyaj disiplini: doğrula, kapsa, sınıflandır, eskale et.</li><li>Model çıktılarında hassas veri sızıntısı taraması = DLP mantığı.</li><li>IR yaşam döngüsü aynen uygulanır — sadece varlık türü yeni (model, prompt, eğitim verisi).</li></ul>Mülakatta köprü cümlesi kur: "Log analizi ve triyaj disiplinim AI sistemlerine doğrudan uygulanır; alert yerine şüpheli prompt deseni koyarsınız, süreç aynıdır."`,
en:`The micro1 role is likely <b>security operations for AI systems</b> — your classic skills transfer directly:<ul><li>Monitor LLM API logs: anomaly patterns (request spikes from one user, systematic jailbreak attempts).</li><li>Injection/jailbreak attempts are the new "alerts" → same triage discipline: validate, scope, classify, escalate.</li><li>Scanning model outputs for sensitive data = DLP logic.</li><li>The IR lifecycle applies unchanged — only the asset types are new (models, prompts, training data).</li></ul>Bridge line for the interview: "My log-analysis and triage discipline applies directly to AI systems; replace the alert with a suspicious prompt pattern and the process is the same."`},
say:`Securing AI systems is still security operations: you monitor logs, detect anomalies like systematic jailbreak attempts, triage them with the same discipline, and run the same incident response lifecycle — the assets are just new: models, prompts and training data.`}
],
quiz:[
{q:{tr:'Indirect prompt injection nedir?', en:'What is indirect prompt injection?'}, opts:[{tr:'Kullanıcının modele küfretmesi', en:'A user insulting the model'},{tr:'Modelin okuduğu içeriğe (web/doküman) gömülü gizli talimat', en:'Hidden instructions embedded in content the model reads (web/docs)'},{tr:'Modelin yavaş cevap vermesi', en:'The model responding slowly'},{tr:'GPU aşırı ısınması', en:'GPU overheating'}], a:1, expl:{tr:'Model, veri sandığı içerikteki talimatı uygular — kullanıcı ve geliştirici farkında olmayabilir.', en:'The model obeys instructions inside what it thinks is data — user and developer may never notice.'}},
{q:{tr:'Jailbreak ile prompt injection farkı?', en:'Jailbreak vs prompt injection?'}, opts:[{tr:'Aynı şey', en:'Same thing'},{tr:'Jailbreak modelin güvenlik kurallarını, injection uygulamanın talimat akışını hedefler', en:'Jailbreak targets model safety rules; injection targets the app\'s instruction flow'},{tr:'Jailbreak donanım saldırısıdır', en:'Jailbreak is a hardware attack'},{tr:'Injection sadece SQL\'de olur', en:'Injection only exists in SQL'}], a:1, expl:{tr:'İkisi sık karışır — bu ayrımı net söylemek artı puan.', en:'Commonly confused — stating this distinction cleanly earns points.'}},
{q:{tr:'RAG bilgi tabanına zehirli doküman eklemek hangi saldırıdır?', en:'Planting a malicious document in a RAG knowledge base is…?'}, opts:[{tr:'DDoS', en:'DDoS'},{tr:'Data poisoning', en:'Data poisoning'},{tr:'MITM', en:'MITM'},{tr:'Port scanning', en:'Port scanning'}], a:1, expl:{tr:'Modelin beslendiği veriyi zehirlemek = poisoning; RAG\'de bilgi tabanı da hedeftir.', en:'Poisoning the data a model consumes — in RAG, the knowledge base is a target too.'}},
{q:{tr:'System prompt\'ta API anahtarı saklamak neden yanlıştır?', en:'Why is storing an API key in the system prompt wrong?'}, opts:[{tr:'Token maliyeti artar', en:'It increases token cost'},{tr:'Prompt extraction ile sızdırılabilir', en:'It can be leaked via prompt extraction'},{tr:'Model yavaşlar', en:'The model slows down'},{tr:'Yanlış değildir', en:'It is not wrong'}], a:1, expl:{tr:'Prompt\'lar çıkarılabilir (extraction); sırlar asla prompt\'a konmaz.', en:'Prompts can be extracted; secrets never belong in prompts.'}},
{q:{tr:'Sistematik jailbreak denemeleri gören bir analiste en doğru yaklaşım?', en:'Best analyst approach to systematic jailbreak attempts?'}, opts:[{tr:'Görmezden gel', en:'Ignore them'},{tr:'Klasik alert triyajı gibi ele al: doğrula, kapsa, sınıflandır, eskale et', en:'Treat like alert triage: validate, scope, classify, escalate'},{tr:'Modeli hemen kapat', en:'Immediately shut the model down'},{tr:'Kullanıcıya teşekkür et', en:'Thank the user'}], a:1, expl:{tr:'AI güvenlik olayları da aynı SOC disipliniyle yönetilir — bu köprüyü kurmak mülakatta güçlü sinyaldir.', en:'AI security events follow the same SOC discipline — making this bridge is a strong interview signal.'}}
]}
];
